import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.SQLException;
import java.util.Properties;

public class DatabaseConnection {
    private static final String DB_URL = "jdbc:postgresql://localhost:5432/demo_db";
    
    public static Connection getConnection() throws SQLException {
        Properties props = new Properties();
        props.setProperty("user", System.getenv("DB_USERNAME") != null ? 
                         System.getenv("DB_USERNAME") : "admin");
        props.setProperty("password", System.getenv("DB_PASSWORD") != null ? 
                         System.getenv("DB_PASSWORD") : "Demo123!");
        props.setProperty("ssl", "false");
        
        return DriverManager.getConnection(DB_URL, props);
    }
    
    public static void main(String[] args) {
        try (Connection conn = getConnection()) {
            System.out.println("Connected to database successfully!");
        } catch (SQLException e) {
            System.err.println("Failed to connect to database: " + e.getMessage());
        }
    }
}